#include <stdio.h>
int nadji_nzd(int, int);
int main() {
long x, y, nzd, nzv;
printf("Unesi dva cijela broja\n");
scanf("%ld%ld", &x, &y);
nzd = nadji_nzd(x, y);
nzv = (x*y) / nzd;
printf("Najveci zajednicki djelitelj %ld i %ld = %ld\n", x, y, nzd);
printf("Najmanji zajednicki visekratnik %ld i %ld = %ld\n", x, y, nzv);
return 0;
}
int nadji_nzd(int a, int b) {
if (b == 0) {
return a;
}
else {
return nadji_nzd(b, a % b);
}
}
