Zadano je polje brojeva s elementima: 91, 7, 8, 20, 5, 18, 4, 9. Ilustrirajte uzlazno sortiranje zadanog niza
brojeva (ispišite polje nakon svake promjene i potcrtajte sve brojeve relevantne za sljedeći korak) algoritmom
shellsort uz korake k = 4, 2, 1
Rješenja
1. (7 bodova)
#include <stdio.h>
#include <string.h>
#define N 10000
#define BLOK 4096
#define C BLOK/sizeof (zapis)
#define M (int)(N * 1.15/C)
typedef struct {
char sifra[10 + 1];
char ime[20 + 1];
char prezime[30 + 1];
int ocjena;
} zapis;
int adresa(int sifra);
int main() {
FILE *f = NULL;
zapis pretinac[C];
int i, j, sumaOcjena = 0, brStudenata = 0;
float prosjecnaOcjena = 0;
f = fopen("podaci.dat", "rb");
/*Dohvat ocjena iz zapisa koji su zavrsili u preljevu*/
for(i = 0; i < M; i++) {
fseek(f, i * BLOK, SEEK_SET);
fread(pretinac, sizeof(pretinac), 1, f);
for(j = 0; j < C; j++) {
if(strcmp(pretinac[j].sifra,"0") == 0) {
/*Prazan zapis - prelazimo na sljedeci pretinac*/
break;
}
if(adresa(pretinac[j].sifra) != i) {
/*Preljev*/
brStudenata++;
sumaOcjena += pretinac[j].ocjena;
}
}
}
/*Racunanje prosjecne ocjene*/
prosjecnaOcjena = (float)sumaOcjena / brStudenata;
/*Na zaslon ispisujemo podatke za studente cija je ocjena >= prosjecnoj ocjeni*/
for(i = 0; i < M; i++) {
fseek(f, i * BLOK, SEEK_SET);
fread(pretinac, sizeof(pretinac), 1, f);
for(j = 0; j < C; j++) {
if(strcmp(pretinac[j].sifra,"0") == 0) {
/*Prazan zapis - prelazimo na sljedeci pretinac*/
break;
}
if(adresa(pretinac[j].sifra) == i && pretinac[j].ocjena >= prosjecnaOcjena) {
/*Zapis koji nije preljev*/
printf("%-11s%-30s%-20s%-9d\n",
pretinac[j].sifra,
pretinac[j].prezime,
pretinac[j].ime,
pretinac[j].ocjena
);
}
}
}
fclose(f);
return 0;
}
2. (5 bodova)
int kvazi_binomni(int n, int m) {
if( ( n < 0 ) || ( m > n ) ) return 0;
if( ( m == 0 ) || ( n == m ) ) return 1;
return kvazi_binomni( n - 1, m - 1 )
+ m * kvazi_binomni( n - 1, m + 1 );
}
3. (5 bodova)
int najveci_eksponent(int n, int m){
int dalje, eksponent=0;
if (n<m) return 0; /* Osnovni slucaj */
while(n % m == 0){ /* Koliko puta m dijeli n */
eksponent++;
n /= m;
}
dalje= najveci_eksponent (n,m+1); /* Rekurzivno napredovanje */
if (dalje>eksponent) return dalje; /* Veci se vraca pozivajucoj proceduri */
return eksponent;
}
