int prebroji_znamenke(int broj, int znamenka)
{
//Negativni broj pretvori u pozitivan
if (broj < 0) broj *= -1;
//Sve znamenke do zadnje
if (broj > 10)
{
if (broj % 10 == znamenka) return 1 + prebroji_znamenke(broj/10, znamenka);
else return prebroji_znamenke(broj/10, znamenka);
}
//Zadnja znamenka – uvjet završetka – funkcionira i za ulaz (0,0)
