void qsort(int* niz, int lijevo, int desno){
int stozerInd;
if(lijevo >= desno)
return;
stozerInd = medijan(niz, lijevo, desno);
stozerInd = preslozi(niz, stozerInd, lijevo, desno);
qsort(niz, lijevo, stozerInd - 1);
qsort(niz, stozerInd + 1, desno);
}
