void izbaci(Red *red){
int preth, tren;
Red pom;
init_red(&pom);
skini(&preth, red); /*po pretpostavci zadatka postoji barem jedan*/
while(skini(&tren, red)){
if (preth > tren){
dodaj(preth, &pom);
}
preth = tren;
}
dodaj(preth, &pom); /*zadnji element u redu*/
while(skini(&tren, &pom))
dodaj(tren, red);
}
