void izbaci_duplikate(Red *red){
Stog stog;Red pom; int el;
init_red(&pom); init_stog(&stog);
while(skini_iz_reda(&el, red)){
if (!sadrzi(&stog, el)){
dodaj(el, &stog);
dodaj_u_red(el, &pom);
}
}
/*ispraznimo stog*/
while(skini(&el, &stog));
while(skini_iz_reda(&el, &pom))
dodaj_u_red(el, red);
}
