void IzbaciUzastopne(Red *red){
Red pom; int element, prethodni;
init_red(&pom);
if (skini(&element, red)){
prethodni = element;
dodaj(element, &pom);
while(skini(&element, red)){
if (element != prethodni)
dodaj(element, &pom);
prethodni = element;
}
while(skini(&element, &pom)){
dodaj(element, red);
}
}
}
