Stog *veci_od_prosjeka(Stog *zadani){
Stog *novi = new Stog(), pom;
int suma=0, el, br=0; float prosjek;
while(!zadani->Prazan()){
zadani->Skini(&el);
pom.Stavi(el);
suma+=el; br++;
}
if (br>0)
prosjek = (float) suma / br;
while(!pom.Prazan()){
pom.Skini(&el);
zadani->Stavi(el);
if (el >= prosjek)
novi->Stavi(el);
}
printf("Prosjek = %.2f", prosjek);
return novi;
}
