// pomoćni funkcijski članovi (protected):
void dodaj(shared_ptr<Cvor>& cvor, const T& noviElem) {
if (cvor) {
if (cvor->elem < noviElem)
dodaj(cvor->desno, noviElem);
else if (cvor->elem > noviElem)
dodaj(cvor->lijevo, noviElem);
else {} // ne treba ništa, jer element postoji u stablu
}
else {
cvor = std::make_shared<Cvor>(noviElem);
}
}
// sve elemente koji ne postoje u trenutnom stablu, a postoje u novom stablu, dodati u
// trenutno stablo
void dodajNove(shared_ptr<Cvor>& korijen, shared_ptr<Cvor>& korijenNovi) {
// npr. inorder obilazak pomoćnog stabla;
if (korijenNovi) {
if (korijenNovi->lijevo)
dodajNove(korijen, korijenNovi->lijevo);
// dodaj novi element, ako ne postoji u stablu
dodaj(korijen, korijenNovi->elem);
if (korijenNovi->desno)
dodajNove(korijen, korijenNovi->desno);
}
}
// odsječak glavnog programa, npr.
