4. zadatak
#define M 50000
#define KOEF 0.6
template < typename T, typename K>
class HashLinearHashing : public IHash<T, K> {
private:
void Empty() {
size_t i;
for (i = 0; i < this->size; i++) {
this->hash[i] = nullptr;
}
}
//Method1 nije potrebno pisati
int Method1(int id) const { return id % M; }
public:
void Add(IHashableValue<T, K>* element) {
int h1 = Method1(element->GetKey());
int index;
for (int i = 0; i < this->size; i++) {
index = (h1 + i) % this->size;
if (this->hash[index] == nullptr) {
this->hash[index] = element;
break;
}
}
}
IHashableValue<T, K>* Get(K key) {
int h1 = Method1(key);
int index;
for (int i = 0; i < this->size; i++) {
index = (h1 + i) % this->size;
if (this->hash[index] != nullptr && (*this->hash[index]).GetKey() == key) {
return this->hash[index];
}
}
return nullptr;
}
//kontruktor nije potrebno pisati
HashLinearHashing(size_t size) {
this->size = size;
this->hash = new IHashableValue<T, K>*[this->size];
this->Empty();
}
float GetLoadFactor() {
float n = 0;
for (int i = 0; i < this->size; i++) {
if (this->hash[i] != nullptr) { n++; }
}
return n/this->size;
}
};
//ovu klasu nije potrebno pisati
class HashElem : public IHashableValue<HashElem, int> {
public:
int id;
HashElem(int id = 0) : id(id) { }
virtual int GetKey() const { return id; }
};
int main() {
HashLinearHashing<HashElem, int> hash(M);
HashElem elem[M];
srand(time(NULL)); // srand(time(nullptr));
for (int i = 0; i < M; i++) {
elem[i] = rand() % 9001 + 1000;
hash.Add(&elem[i]);
if (hash. GetLoadFactor () > KOEF)
break;
}
cout << hash.GetLoadFactor() << endl;
}
