a)
// javni funkcijski član:
bool jesuPotomci (const T& a, const T& b, const T& c) {
return jesuPotomci(korijen, a, b, c);
}
// pomoćni funkcijski članovi (protected):
bool trazi(shared_ptr<Node>& cvor, const T& elem) {
if (cvor) {
if (cvor->elem < elem)
return trazi(cvor->desno, elem);
else if (cvor->elem > elem)
return trazi(cvor->lijevo, elem);
else // nadjen
return true;
}
return false;
}
bool jesuPotomci(shared_ptr<Node>& cvor, const T& a, const T& b, const T& c) {
if (cvor) {
if (cvor->elem == c) {
bool nadjenA = a < c ? trazi(cvor->lijevo, a) : trazi(cvor->desno, a);
bool nadjenB = b < c ? trazi(cvor->lijevo, b) : trazi (cvor->desno, b);
return nadjenA && nadjenB;
}
else if (cvor->elem < c) {
return jesuPotomci(cvor->desno, a, b, c);
}
else {
return jesuPotomci(cvor->lijevo, a, b, c);
}
}
return false;
}
