// javni funkcijski član:
int brojPuteva(T elem) {
return brojPuteva (korijen, elem);
}
// pomoćni funkcijski član (protected):
int brojPuteva (shared_ptr<Cvor>& cvor, T elem) {
if (!cvor) return 0;
// list
if (!cvor->lijevo && !cvor->desno)
return cvor->elem < elem ? 1: 0;
// unutarnji čvor ili korijen
if (cvor->elem >= elem) return 0;
// else
int brLijevo = brojPuteva (cvor->lijevo, elem);
int brDesno = brojPuteva (cvor->desno, elem);
return brLijevo + brDesno;
}
