4. zadatak
Stog::Stog(Red *stari, int n){
int i = 1;tip element;Red pom;
this->vrh = NULL;
while(stari->Skini(&element)){
if (i<=n){
pom.Dodaj(element);
this->Dodaj(element);
i++;
}
else
pom.Dodaj(element);
}
while(pom.Skini(&element)){
stari->Dodaj(element);
}
}
Red* Stog::URed(int n){
int i = 1;tip element;
Red *novi = new Red();
Stog pom;
while(i<=n && this->Skini(&element)){
novi->Dodaj(element);
pom.Dodaj(element);
i++;
}
while(pom.Skini(&element)){
this->Dodaj(element);
}
return novi;
}
