1. (7 bodova) Ukoliko je red, koji sadrži cijele brojeve, realiziran listom, napisati
funkcije za dodavanje novog elementa u red i skidanje elementa iz reda. Također,
deklarirati sve potrebne strukture za navedenu implementaciju i napisati odsječak
glavnog programa koji demonstrira korištenje navedenih funkcija.
Dodavanje 3 boda
Skidanje 3 boda
glavni prog 1 bod
typedef struct at atom;
struct at {
int element;
struct at *sljed;
};
int DodajURed (int element, atom **ulaz, atom **izlaz) {
atom *novi;
if (novi = malloc (sizeof (atom))) {
novi->element = element;
novi->sljed = NULL;
if (*izlaz == NULL) *izlaz = novi;
else (*ulaz)->sljed = novi;
*ulaz = novi;
return 1;
}
return 0;
}
int SkiniIzReda (int *element, atom **ulaz, atom **izlaz) {
atom *stari;
if (*izlaz) {
*element = (*izlaz)->element;
stari = *izlaz;
*izlaz = (*izlaz)->sljed;
free (stari);
if (*izlaz == NULL) *ulaz = NULL;
return 1;
}
return 0;
}
